'use client';

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { X, AlertTriangle, Check, Info } from 'lucide-react';

type ConfirmOptions = {
  title?: string;
  message: string;
  confirmLabel?: string;
  cancelLabel?: string;
  type?: 'danger' | 'info' | 'success';
};

type ConfirmContextType = {
  confirm: (options: ConfirmOptions) => Promise<boolean>;
};

const ConfirmContext = createContext<ConfirmContextType | undefined>(undefined);

export function ConfirmProvider({ children }: { children: ReactNode }) {
  const [isOpen, setIsOpen] = useState(false);
  const [options, setOptions] = useState<ConfirmOptions | null>(null);
  const [resolvePromise, setResolvePromise] = useState<(value: boolean) => void>(() => {});

  const confirm = (opts: ConfirmOptions) => {
    setOptions(opts);
    setIsOpen(true);
    return new Promise<boolean>((resolve) => {
      setResolvePromise(() => resolve);
    });
  };

  const handleClose = (result: boolean) => {
    setIsOpen(false);
    resolvePromise(result);
  };

  return (
    <ConfirmContext.Provider value={{ confirm }}>
      {children}
      {isOpen && options && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 animate-in fade-in duration-200">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => handleClose(false)} />
          <div className={`relative w-full max-w-md bg-white dark:bg-[#1a0f38] border-[4px] border-black dark:border-white/20 rounded-3xl p-8 shadow-[12px_12px_0_#000] dark:shadow-[12px_12px_0_rgba(255,255,255,0.1)] transform animate-in zoom-in-95 duration-200`}>
            <div className="flex flex-col items-center text-center gap-4">
              <div className={`w-16 h-16 rounded-2xl border-[3px] border-black flex items-center justify-center shadow-[4px_4px_0_#000]
                ${options.type === 'danger' ? 'bg-rose-500 text-white' : 
                  options.type === 'success' ? 'bg-emerald-500 text-white' : 'bg-[#6c40d6] text-white'}`}>
                {options.type === 'danger' ? <AlertTriangle size={36} strokeWidth={2.5} /> : 
                 options.type === 'success' ? <Check size={36} strokeWidth={2.5} /> : <Info size={36} strokeWidth={2.5} />}
              </div>
              
              <h2 className="text-2xl font-black uppercase tracking-tight dark:text-white mt-2">
                {options.title || 'Confirmar'}
              </h2>
              
              <p className="text-slate-600 dark:text-slate-400 font-bold leading-relaxed">
                {options.message}
              </p>

              <div className="flex flex-col sm:flex-row gap-3 w-full mt-6">
                <button
                  onClick={() => handleClose(false)}
                  className="flex-1 px-6 py-3 border-[3px] border-black rounded-xl font-black text-sm hover:bg-slate-100 dark:hover:bg-white/5 dark:text-white dark:border-white/20 transition-all uppercase tracking-widest"
                >
                  {options.cancelLabel || 'Cancelar'}
                </button>
                <button
                  onClick={() => handleClose(true)}
                  className={`flex-1 px-6 py-3 border-[4px] border-black rounded-xl font-black text-sm text-white shadow-[4px_4px_0_#000] active:translate-x-1 active:translate-y-1 active:shadow-none transition-all uppercase tracking-widest
                    ${options.type === 'danger' ? 'bg-rose-500 hover:bg-rose-600' : 
                      options.type === 'success' ? 'bg-emerald-500 hover:bg-emerald-600' : 'bg-[#6c40d6] hover:bg-[#5b3eb8]'}`}
                >
                  {options.confirmLabel || 'Aceptar'}
                </button>
              </div>
            </div>
            <button 
              onClick={() => handleClose(false)}
              className="absolute top-4 right-4 text-slate-400 hover:text-black dark:hover:text-white transition-colors"
            >
              <X size={24} />
            </button>
          </div>
        </div>
      )}
    </ConfirmContext.Provider>
  );
}

export function useConfirm() {
  const context = useContext(ConfirmContext);
  if (!context) throw new Error('useConfirm must be used within ConfirmProvider');
  return context;
}
